// Extract Kochi Metro booking URL from the incoming WhatsApp message
// Twilio sends WhatsApp data as form-urlencoded body
const body = $input.first().json.body;

// Handle both direct body access and nested body from webhook
const messageBody = body.Body || body.body || '';
const senderNumber = body.From || body.from || '';
const recipientNumber = body.To || body.to || '';

// Log for debugging
console.log('Incoming message:', messageBody);
console.log('From:', senderNumber);
console.log('To:', recipientNumber);

// Regex to extract Kochi Metro booking URL
// Matches: https://prutech.org/KMRL/#/manage/ticket/<anything>
const urlRegex = /https?:\/\/prutech\.org\/KMRL\/#\/manage\/ticket\/[A-Za-z0-9_-]+/g;
const matches = messageBody.match(urlRegex);

if (!matches || matches.length === 0) {
  // No valid URL found — return error flag
  return [{
    json: {
      hasValidUrl: false,
      error: "Couldn't find a valid Kochi Metro booking link.",
      senderNumber: senderNumber,
      recipientNumber: recipientNumber,
      rawMessage: messageBody
    }
  }];
}

// Use the first matching URL
const bookingUrl = matches[0];

// Remove the URL from the message to get remaining text for journey parsing
const remainingText = messageBody.replace(urlRegex, '').trim();

return [{
  json: {
    hasValidUrl: true,
    bookingUrl: bookingUrl,
    remainingText: remainingText,
    rawMessage: messageBody,
    senderNumber: senderNumber,
    recipientNumber: recipientNumber
  }
}];

// Parse journey details from the remaining message text
// Supports multiple formats:
// - "from X to Y" / "X -> Y" / "X to Y"
// - "N passengers" / "for N people" / "N ticket(s)"
// - Line-by-line: origin, destination, passengers

const data = $input.first().json;
const text = data.remainingText || '';

let origin = null;
let destination = null;
let passengers = null;

// ===== PASSENGER EXTRACTION =====
// Number words mapping
const numberWords = {
  'one': 1, 'two': 2, 'three': 3, 'four': 4, 'five': 5,
  'six': 6, 'seven': 7, 'eight': 8, 'nine': 9, 'ten': 10
};

// Try: "N passengers", "N people", "N ticket(s)", "for N"
const passengerPatterns = [
  /(\d+)\s*(?:passengers?|people|persons?|ticket[s]?|pax)/i,
  /(?:for|with)\s+(\d+)\s*(?:passengers?|people|persons?|ticket[s]?|pax)?/i,
  /(one|two|three|four|five|six|seven|eight|nine|ten)\s*(?:passengers?|people|persons?|ticket[s]?|pax)/i,
  /(?:for|with)\s+(one|two|three|four|five|six|seven|eight|nine|ten)/i
];

for (const pattern of passengerPatterns) {
  const match = text.match(pattern);
  if (match) {
    const val = match[1];
    passengers = numberWords[val.toLowerCase()] || parseInt(val, 10);
    if (!isNaN(passengers) && passengers > 0) break;
    passengers = null;
  }
}

// ===== STATION EXTRACTION =====
// Known Kochi Metro stations for fuzzy matching
const stations = [
  'Aluva', 'Pulinchodu', 'Companypady', 'Ambattukavu', 'Muttom',
  'Kalamassery', 'CUSAT', 'Pathadipalam', 'Edappally', 'Changampuzha Park',
  'Palarivattom', 'JLN Stadium', 'Kaloor', 'Town Hall', 'MG Road',
  'Maharajas College', 'Ernakulam South', 'Kadavanthra', 'Elamkulam',
  'Vyttila', 'Thaikoodam', 'Pettah', 'Vadakkekotta', 'SN Junction',
  'Thrippunithura', 'Eroor', 'Chottanikkara'
];

// Helper: find best matching station name (case-insensitive)
function findStation(input) {
  if (!input) return null;
  const clean = input.trim();
  // Exact match (case-insensitive)
  const exact = stations.find(s => s.toLowerCase() === clean.toLowerCase());
  if (exact) return exact;
  // Partial match
  const partial = stations.find(s => s.toLowerCase().includes(clean.toLowerCase()) || clean.toLowerCase().includes(s.toLowerCase()));
  if (partial) return partial;
  // If no match in known stations, return as-is (preserve user input)
  return clean;
}

// Try pattern: "from X to Y"
const fromToPattern = /(?:from|travel from|travelling from)\s+(.+?)\s+(?:to|->|→|–)\s+(.+?)(?:\s+(?:with|for|,|$))/i;
const fromToMatch = text.match(fromToPattern);

if (fromToMatch) {
  origin = findStation(fromToMatch[1]);
  destination = findStation(fromToMatch[2].replace(/\s*(with|for|,|\d+).*$/i, '').trim());
}

// Try pattern: "X to Y" / "X -> Y" / "X → Y" (without 'from')
if (!origin || !destination) {
  const simpleToPattern = /([A-Za-z\s]+?)\s*(?:to|->|→|–)\s*([A-Za-z\s]+?)(?:\s*(?:with|for|,|\d+|$))/i;
  const simpleMatch = text.match(simpleToPattern);
  if (simpleMatch) {
    const candidateOrigin = simpleMatch[1].replace(/^(?:book|travel|go|heading)\s*/i, '').trim();
    const candidateDest = simpleMatch[2].replace(/\s*(with|for|,|\d+).*$/i, '').trim();
    if (candidateOrigin && candidateDest) {
      origin = origin || findStation(candidateOrigin);
      destination = destination || findStation(candidateDest);
    }
  }
}

// Try line-by-line format (origin on one line, destination on next)
if (!origin || !destination) {
  const lines = text.split(/\n/).map(l => l.trim()).filter(l => l && !l.match(/^(book|this|please|hi|hello|hey)/i) && !l.match(/\d+\s*(passengers?|people|ticket)/i));
  if (lines.length >= 2) {
    origin = origin || findStation(lines[0]);
    destination = destination || findStation(lines[1]);
  } else if (lines.length === 1) {
    // Single station mentioned — could be destination
    const singleStation = findStation(lines[0]);
    if (singleStation && stations.some(s => s.toLowerCase() === singleStation.toLowerCase())) {
      destination = destination || singleStation;
    }
  }
}

// ===== APPLY DEFAULTS =====
origin = origin || 'Aluva';
destination = destination || 'Palarivattom';
passengers = passengers || 1;

// Ensure passengers is a valid positive integer
passengers = Math.max(1, Math.min(10, Math.floor(passengers)));

console.log('Parsed journey:', { origin, destination, passengers });

return [{
  json: {
    url: data.bookingUrl,
    origin: origin,
    destination: destination,
    passengers: passengers,
    senderNumber: data.senderNumber,
    recipientNumber: data.recipientNumber,
    rawMessage: data.rawMessage
  }
}];

// Build the success WhatsApp reply message
const apiResponse = $input.first().json;
const journeyData = $('Parse Journey Details').first().json;

// Extract the payment/deeplink URL from the API response
const paymentUrl = apiResponse.payment_url || apiResponse.url || apiResponse.deeplink || '';

let message;
if (paymentUrl) {
  message = `🚇 *Your Kochi Metro booking is ready!*\n\n` +
    `🔹 *Route:* ${journeyData.origin} → ${journeyData.destination}\n` +
    `🔹 *Passengers:* ${journeyData.passengers}\n\n` +
    `💳 *Pay here:*\n${paymentUrl}`;
} else {
  // API returned success but no URL — unusual, still report
  message = `🚇 *Kochi Metro booking processed!*\n\n` +
    `🔹 *Route:* ${journeyData.origin} → ${journeyData.destination}\n` +
    `🔹 *Passengers:* ${journeyData.passengers}\n\n` +
    `⚠️ No payment URL returned. Please check the metro app.`;
}

return [{
  json: {
    message: message,
    senderNumber: journeyData.senderNumber,
    recipientNumber: journeyData.recipientNumber
  }
}];

// Build the failure WhatsApp reply message
const apiResponse = $input.first().json;
const journeyData = $('Parse Journey Details').first().json;

// Extract error message
const errorMsg = apiResponse.error || apiResponse.message || 'Unknown error occurred';

const message = `❌ *Booking failed*\n\n` +
  `🔹 *Route:* ${journeyData.origin} → ${journeyData.destination}\n` +
  `🔹 *Passengers:* ${journeyData.passengers}\n\n` +
  `⚠️ *Error:* ${errorMsg}\n\n` +
  `Please try again or contact support.`;

return [{
  json: {
    message: message,
    senderNumber: journeyData.senderNumber,
    recipientNumber: journeyData.recipientNumber
  }
}];

// Build error reply when no valid booking URL was found
const data = $input.first().json;

return [{
  json: {
    message: "❌ *Couldn't find a valid Kochi Metro booking link.*\n\nPlease send a message containing a valid booking URL like:\nhttps://prutech.org/KMRL/#/manage/ticket/ABC123\n\nYou can optionally include journey details:\n• From [origin] to [destination]\n• Number of passengers",
    senderNumber: data.senderNumber,
    recipientNumber: data.recipientNumber
  }
}];

// Handle HTTP Request errors (network failures, API down, etc.)
const journeyData = $('Parse Journey Details').first().json;
const errorData = $input.first().json;

const errorMsg = errorData.error || errorData.message || errorData.statusMessage || 'The booking service is temporarily unavailable';

const message = `❌ *Booking request failed*\n\n` +
  `🔹 *Route:* ${journeyData.origin} → ${journeyData.destination}\n` +
  `🔹 *Passengers:* ${journeyData.passengers}\n\n` +
  `⚠️ *Error:* ${errorMsg}\n\n` +
  `The booking service may be temporarily down. Please try again in a few minutes.`;

return [{
  json: {
    message: message,
    senderNumber: journeyData.senderNumber,
    recipientNumber: journeyData.recipientNumber
  }
}];
